<?php
$applications = $applications ?? [];
$offerCount = count($applications);
$verifiedCount = count(array_filter($applications, static fn($row) => ($row['verification_status'] ?? '') === 'Verified'));
$acceptedCount = count(array_filter($applications, static fn($row) => in_array(($row['offer_status'] ?? ''), ['Accepted', 'Hired'], true)));
$hiredCount = count(array_filter($applications, static fn($row) => ($row['offer_status'] ?? '') === 'Hired' || ($row['application_status'] ?? '') === 'Hired'));
$statusClass = static function (string $status): string { return match ($status) { 'Verified', 'Accepted', 'Hired' => 'border-emerald-200 bg-emerald-50 text-emerald-700', 'Failed', 'Declined', 'Rejected' => 'border-rose-200 bg-rose-50 text-rose-700', 'Sent', 'Documents Requested', 'Documents Submitted' => 'border-blue-200 bg-blue-50 text-blue-700', default => 'border-slate-200 bg-slate-50 text-slate-600' }; };
?>
<!DOCTYPE html>
<html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Offers & Onboarding | GICHRMS</title><script src="https://cdn.tailwindcss.com"></script><script src="https://unpkg.com/lucide@latest"></script><link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800;900&display=swap" rel="stylesheet"><style>body{font-family:Inter,system-ui,sans-serif}</style></head>
